CREATE TABLE `history` (
  `id` int NOT NULL,
  `job_description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `best_cv_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `similarity_score` float NOT NULL,
  `user_id` int DEFAULT NULL,
  `best_cv_text` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `best_cv_path2` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `best_cv_path3` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `similarity_score2` float DEFAULT NULL,
  `similarity_score3` float DEFAULT NULL,
  `best_cv_text2` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `best_cv_text3` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

